sys_atf_test_step.step:
(function step(assert, $library) {
    // Test External Entities CRUD operations
    // Create
    var gr = new GlideRecord('u_idp_external_entity');
    gr.initialize();
    gr.u_name = 'Test External Entity ATF';
    gr.u_type = 'test';
    gr.u_external_id = 'ext-001';
    var id = gr.insert();
    assert.isTrue(id, 'External entity should be created');

    // Read
    gr = new GlideRecord('u_idp_external_entity');
    gr.get(id);
    assert.equal(gr.u_name, 'Test External Entity ATF', 'External entity name should match');

    // Update
    gr.u_external_id = 'ext-002';
    gr.update();

    // Delete
    gr.deleteRecord();

    // Verify deletion
    gr = new GlideRecord('u_idp_external_entity');
    gr.get(id);
    assert.isFalse(gr.isValid(), 'External entity should be deleted');
})(step, $library);
